const allItems = $input.all();
const rows = [];

// Função auxiliar para converter strings monetárias em floats limpos para o banco
function parseValue(val) {
  if (!val) return 0;
  return parseFloat(val.trim().replace(/\s/g, '').replace('R$', '').replace(/\./g, '').replace(',', '.'));
}

for (const item of allItems) {
  const textArray = item.json.text || [];
  const submittedAt = item.json.submittedAt;
  const fullText = textArray.join('\n');

  // 1. EXTRAÇÃO DINÂMICA DA DATA DE REFERÊNCIA (Ex: "Data: 06/2026" vira "2026-06")
  let dataReferencia = null;
  const dateMatch = fullText.match(/Data:\s*(\d{2})\/(\d{4})/i);
  if (dateMatch) {
    dataReferencia = `${dateMatch[2]}-${dateMatch[1]}`;
  }

  // Normaliza quebras de linha que costumam separar o símbolo R$ dos números
  const cleanText = fullText
    .replace(/\r/g, '')
    .replace(/\n\s*R\$\s*/g, ' R$ ')
    .replace(/R\$\s*\n\s*/g, ' R$ ');

  // 2. DIVISÃO DINÂMICA POR SEÇÕES (Garante que Proventos não vazem para o Tesouro)
  const sections = cleanText.split(/(?=Posição\s*-\s*|Proventos\s+recebidos|Negociação)/i);

  for (const sectionText of sections) {
    if (!sectionText.trim()) continue;

    // Descobre o título real da seção para saber como tratá-la
    const titleLine = sectionText.split('\n')[0].trim();
    let category = titleLine.replace(/^Posição\s*-\s*/i, '').split('-')[0].trim();

    // Comprime múltiplos espaços e quebras de linha para estabilizar o comportamento do Regex
    const cleanSection = sectionText.replace(/\s+/g, ' ').trim();

    // =========================================================================
    // REGRA A: RENDA VARIÁVEL (Ações, FIIs, BDRs, ETFs, Fundos)
    // =========================================================================
    if (['Ações', 'BDR', 'ETF', 'FII', 'Fundos de Investimentos'].some(cat => titleLine.includes(cat))) {
      // Captura: Ticker (1), Nome Ativo (2), Tipo (3), Instituição (4), Qtd (5), Preço (6), Total (7)
      const assetRegex = /([A-Z]{4}\d{1,2})\s*-\s*(.+?)\s+(UNIT|ON|PN|Cotas|Direito|Fundo|Ações|BDR)\s+(.+?)\s+(\d+)\s+R\$\s*([\d.,]+)\s+R\$\s*([\d.,]+)/gi;
      let match;
      while ((match = assetRegex.exec(cleanSection)) !== null) {
        rows.push({
          ticker: match[1].toUpperCase(),
          nome_ativo: match[2].trim(),
          tipo_ativo: match[3].trim(),
          instituicao: match[4].trim(), // Captura qualquer corretora/banco textualmente aqui
          categoria: category,
          quantidade: parseInt(match[5], 10),
          preco_fechamento: parseValue(match[6]),
          valor_atualizado: parseValue(match[7]),
          tipo_registro: 'Posição Custódia',
          data_referencia: dataReferencia,
          submitted_at: submittedAt
        });
      }
    }

    // =========================================================================
    // REGRA B: TESOURO DIRETO
    // =========================================================================
    else if (titleLine.includes('Tesouro Direto')) {
      // Captura o título do Tesouro, a instituição no meio e os valores no fim de forma posicional
      const tesouroRegex = /(Tesouro\s+[A-Za-z0-9\s]+?)\s+(.+?)\s+(\d{2}\/\d{2}\/\d{4})\s+([\d.,]+)\s+R\$\s*([\d.,]+)\s+R\$\s*([\d.,]+)/gi;
      let match;
      while ((match = tesouroRegex.exec(cleanSection)) !== null) {
        rows.push({
          ticker: 'TESOURO',
          nome_ativo: match[1].trim(),
          tipo_ativo: 'Título Público',
          instituicao: match[2].trim(), // Dinâmico
          categoria: 'Tesouro Direto',
          quantidade: parseValue(match[4]),
          preco_fechamento: 0,
          valor_atualizado: parseValue(match[6]),
          tipo_registro: 'Posição Custódia',
          data_referencia: dataReferencia,
          submitted_at: submittedAt
        });
      }
    }

    // =========================================================================
    // REGRA C: RDB (Recibo de Depósito Bancário)
    // =========================================================================
    else if (titleLine.includes('RDB')) {
      const rdbRegex = /(RDB\s*-?\s*.+?)\s+(\d{2}\/\d{2}\/\d{4})\s+(\d+)\s+R\$\s*([\d.,]+)\s+R\$\s*([\d.,]+)/gi;
      let match;
      while ((match = rdbRegex.exec(cleanSection)) !== null) {
        let rdbText = match[1].replace(/^RDB\s*-?\s*/i, '').trim();

        // Como o PDF costuma duplicar o nome do banco (Produto e Instituição colados), 
        // testamos se a string se repete e dividimos ao meio de forma inteligente
        let halfLength = Math.floor(rdbText.length / 2);
        let firstHalf = rdbText.substring(0, halfLength).trim();
        let secondHalf = rdbText.substring(halfLength).trim();

        let instituicao = rdbText;
        let nomeAtivo = match[1].trim();

        if (firstHalf === secondHalf || secondHalf.includes(firstHalf)) {
          instituicao = firstHalf;
          nomeAtivo = "RDB - " + firstHalf;
        }

        rows.push({
          ticker: 'RDB',
          nome_ativo: nomeAtivo,
          tipo_ativo: 'Renda Fixa',
          instituicao: instituicao, // Dinâmico (ex: CRESOL, Nu, etc.)
          categoria: 'RDB',
          quantidade: parseInt(match[3], 10),
          preco_fechamento: parseValue(match[4]),
          valor_atualizado: parseValue(match[5]),
          tipo_registro: 'Posição Custódia',
          data_referencia: dataReferencia,
          submitted_at: submittedAt
        });
      }
    }


    // =========================================================================
    // REGRA E: NEGOCIAÇÕES NO PERÍODO
    // =========================================================================
    else if (titleLine.includes('Negociação') || titleLine.includes('Resumo dos negócios')) {
      const negociaoRegex = /([A-Z]{4}\d{1,2}[A-Z]?)\s+(\d{2}\/\d{2}\/\d{4})\s+(.+?)\s+(\d+)\s+(\d+)\s+(\d+)\s+R\$\s*([\d.,]+)\s+R\$\s*([\d.,]+)/gi;
      let match;
      while ((match = negociaoRegex.exec(cleanSection)) !== null) {
        rows.push({
          ticker: match[1].toUpperCase(),
          nome_ativo: 'Negociação de Ativo',
          tipo_ativo: 'Movimentação',
          instituicao: match[3].trim(),
          categoria: 'Negociação',
          quantidade: parseInt(match[6], 10), // Quantidade Líquida
          preco_fechamento: parseValue(match[7]), // Preço Médio Compra
          valor_atualizado: parseValue(match[8]), // Preço Médio Venda
          tipo_registro: 'Negociação',
          data_referencia: dataReferencia,
          submitted_at: submittedAt
        });
      }
    }
  }
}

return rows;

